    29→} from './asymmetricMatchers';
    30→import extractExpectedAssertionsErrors from './extractExpectedAssertionsErrors';
    31→import {
    32→  INTERNAL_MATCHER_FLAG,
    33→  addCustomEqualityTesters,
    34→  getCustomEqualityTesters,
    35→  getMatchers,
    36→  getState,
    37→  setMatchers,
    38→  setState,
    39→} from './jestMatchersObject';
    40→import matchers from './matchers';
    41→import spyMatchers from './spyMatchers';
    42→import toThrowMatchers, {
    43→  createMatcher as createThrowMatcher,
    44→} from './toThrowMatchers';
    45→import type {
    46→  Expect,
    47→  ExpectationResult,
    48→  MatcherContext,
    49→  MatcherState,
    50→  MatcherUtils,
    51→  MatchersObject,
    52→  PromiseMatcherFn,
    53→  RawMatcherFn,
    54→  SyncExpectationResult,
    55→  ThrowingMatcherFn,
    56→} from './types';
    57→
    58→export type {Tester, TesterContext} from '@jest/expect-utils';
    59→export {AsymmetricMatcher} from './asymmetricMatchers';
    60→export type {
    61→  AsyncExpectationResult,
    62→  AsymmetricMatchers,
    63→  BaseExpect,
    64→  Expect,
    65→  ExpectationResult,
    66→  Inverse,
    67→  MatcherContext,
    68→  MatcherFunction,
    69→  MatcherFunctionWithContext,
    70→  MatcherState,
    71→  MatcherUtils,
    72→  Matchers,
    73→  SyncExpectationResult,
    74→} from './types';
    75→
    76→export class JestAssertionError extends Error {
    77→  matcherResult?: Omit<SyncExpectationResult, 'message'> & {message: string};
    78→}
    79→
    80→const createToThrowErrorMatchingSnapshotMatcher = function (
    81→  matcher: RawMatcherFn,
    82→) {
    83→  return function (
    84→    this: MatcherContext,
    85→    received: any,
    86→    testNameOrInlineSnapshot?: string,
    87→  ) {
    88→    return matcher.apply(this, [received, testNameOrInlineSnapshot, true]);
    89→  };
    90→};
    91→
    92→const getPromiseMatcher = (name: string, matcher: RawMatcherFn) => {
    93→  if (name === 'toThrow') {
    94→    return createThrowMatcher(name, true);
    95→  } else if (
    96→    name === 'toThrowErrorMatchingSnapshot' ||
    97→    name === 'toThrowErrorMatchingInlineSnapshot'
    98→  ) {
    99→    return createToThrowErrorMatchingSnapshotMatcher(matcher);
   100→  }
   101→
   102→  return null;
   103→};
   104→
   105→export const expect: Expect = (actual: any, ...rest: Array<any>) => {
   106→  if (rest.length > 0) {
   107→    throw new Error('Expect takes at most one argument.');
   108→  }
   109→
   110→  const allMatchers = getMatchers();
   111→  const expectation: any = {
   112→    not: {},
   113→    rejects: {not: {}},
   114→    resolves: {not: {}},
   115→  };
   116→
   117→  const err = new JestAssertionError();
   118→
   119→  for (const name of Object.keys(allMatchers)) {
   120→    const matcher = allMatchers[name];
   121→    const promiseMatcher = getPromiseMatcher(name, matcher) || matcher;
   122→    expectation[name] = makeThrowingMatcher(matcher, false, '', actual);
   123→    expectation.not[name] = makeThrowingMatcher(matcher, true, '', actual);
   124→
   125→    expectation.resolves[name] = makeResolveMatcher(
   126→      name,
   127→      promiseMatcher,
   128→      false,
   129→      actual,
   130→      err,
   131→    );
   132→    expectation.resolves.not[name] = makeResolveMatcher(
   133→      name,
   134→      promiseMatcher,
   135→      true,
   136→      actual,
   137→      err,
   138→    );
   139→
   140→    expectation.rejects[name] = makeRejectMatcher(
   141→      name,
   142→      promiseMatcher,
   143→      false,
   144→      actual,
   145→      err,
   146→    );
   147→    expectation.rejects.not[name] = makeRejectMatcher(
   148→      name,
   149→      promiseMatcher,
   150→      true,
   151→      actual,
   152→      err,
   153→    );
   154→  }
   155→
   156→  return expectation;
   157→};
   158→
   159→const getMessage = (message?: () => string) =>
   160→  (message && message()) ||
   161→  matcherUtils.RECEIVED_COLOR('No message was specified for this matcher.');
   162→
   163→const makeResolveMatcher =
   164→  (
   165→    matcherName: string,
   166→    matcher: RawMatcherFn,
   167→    isNot: boolean,
   168→    actual: Promise<any>,
   169→    outerErr: JestAssertionError,
   170→  ): PromiseMatcherFn =>
   171→  (...args) => {
   172→    const options = {
   173→      isNot,
   174→      promise: 'resolves',
   175→    };
   176→
   177→    if (!isPromise(actual)) {
   178→      throw new JestAssertionError(
   179→        matcherUtils.matcherErrorMessage(
   180→          matcherUtils.matcherHint(matcherName, undefined, '', options),
   181→          `${matcherUtils.RECEIVED_COLOR('received')} value must be a promise`,
   182→          matcherUtils.printWithType(
   183→            'Received',
   184→            actual,
   185→            matcherUtils.printReceived,
   186→          ),
   187→        ),
   188→      );
   189→    }
   190→
   191→    const innerErr = new JestAssertionError();
   192→
   193→    return actual.then(
   194→      result =>
   195→        makeThrowingMatcher(matcher, isNot, 'resolves', result, innerErr).apply(
   196→          null,
   197→          args,
   198→        ),
   199→      error => {
   200→        outerErr.message =
   201→          `${matcherUtils.matcherHint(
   202→            matcherName,
   203→            undefined,
   204→            '',
   205→            options,
   206→          )}\n\n` +
   207→          'Received promise rejected instead of resolved\n' +
   208→          `Rejected to value: ${matcherUtils.printReceived(error)}`;
   209→        throw outerErr;
   210→      },
   211→    );
   212→  };
   213→
   214→const makeRejectMatcher =
   215→  (
   216→    matcherName: string,
   217→    matcher: RawMatcherFn,
   218→    isNot: boolean,
   219→    actual: Promise<any> | (() => Promise<any>),
   220→    outerErr: JestAssertionError,
   221→  ): PromiseMatcherFn =>
   222→  (...args) => {
   223→    const options = {
   224→      isNot,
   225→      promise: 'rejects',
   226→    };
   227→
   228→    const actualWrapper: Promise<any> =
   229→      typeof actual === 'function' ? actual() : actual;
   230→
   231→    if (!isPromise(actualWrapper)) {
   232→      throw new JestAssertionError(
   233→        matcherUtils.matcherErrorMessage(
   234→          matcherUtils.matcherHint(matcherName, undefined, '', options),
   235→          `${matcherUtils.RECEIVED_COLOR(
   236→            'received',
   237→          )} value must be a promise or a function returning a promise`,
   238→          matcherUtils.printWithType(
   239→            'Received',
   240→            actual,
   241→            matcherUtils.printReceived,
   242→          ),
   243→        ),
   244→      );
   245→    }
   246→
   247→    const innerErr = new JestAssertionError();
   248→
   249→    return actualWrapper.then(
   250→      result => {
   251→        outerErr.message =
   252→          `${matcherUtils.matcherHint(
   253→            matcherName,
   254→            undefined,
   255→            '',
   256→            options,
   257→          )}\n\n` +
   258→          'Received promise resolved instead of rejected\n' +
   259→          `Resolved to value: ${matcherUtils.printReceived(result)}`;
   260→        throw outerErr;
   261→      },
   262→      error =>
   263→        makeThrowingMatcher(matcher, isNot, 'rejects', error, innerErr).apply(
   264→          null,
   265→          args,
   266→        ),
   267→    );
   268→  };
   269→
   270→const makeThrowingMatcher = (
   271→  matcher: RawMatcherFn,
   272→  isNot: boolean,
   273→  promise: string,
   274→  actual: any,
   275→  err?: JestAssertionError,
   276→): ThrowingMatcherFn =>
   277→  function throwingMatcher(...args): any {
   278→    let throws = true;
   279→    const utils: MatcherUtils['utils'] = {
   280→      ...matcherUtils,
   281→      iterableEquality,
   282→      subsetEquality,
   283→    };
   284→
   285→    const matcherUtilsThing: MatcherUtils = {
   286→      customTesters: getCustomEqualityTesters(),
   287→      // When throws is disabled, the matcher will not throw errors during test
   288→      // execution but instead add them to the global matcher state. If a
   289→      // matcher throws, test execution is normally stopped immediately. The
   290→      // snapshot matcher uses it because we want to log all snapshot
   291→      // failures in a test.
   292→      dontThrow: () => (throws = false),
   293→      equals,
   294→      utils,
   295→    };
   296→
   297→    const matcherContext: MatcherContext = {
   298→      ...getState<MatcherState>(),
   299→      ...matcherUtilsThing,
   300→      error: err,
   301→      isNot,
   302→      promise,
   303→    };
   304→
   305→    const processResult = (
   306→      result: SyncExpectationResult,
   307→      asyncError?: JestAssertionError,
   308→    ) => {
   309→      _validateResult(result);
   310→
   311→      getState().assertionCalls++;
   312→
   313→      if ((result.pass && isNot) || (!result.pass && !isNot)) {
   314→        // XOR
   315→        const message = getMessage(result.message);
   316→        let error;
   317→
   318→        if (err) {
   319→          error = err;
   320→          error.message = message;
   321→        } else if (asyncError) {
   322→          error = asyncError;
   323→          error.message = message;
   324→        } else {
   325→          error = new JestAssertionError(message);
   326→
   327→          // Try to remove this function from the stack trace frame.
   328→          // Guard for some environments (browsers) that do not support this feature.
   329→          if (Error.captureStackTrace) {
   330→            Error.captureStackTrace(error, throwingMatcher);
   331→          }
   332→        }
   333→        // Passing the result of the matcher with the error so that a custom
   334→        // reporter could access the actual and expected objects of the result
   335→        // for example in order to display a custom visual diff
   336→        error.matcherResult = {...result, message};
   337→
   338→        if (throws) {
   339→          throw error;
   340→        } else {
   341→          getState().suppressedErrors.push(error);
   342→        }
   343→      } else {
   344→        getState().numPassingAsserts++;
   345→      }
   346→    };
   347→
   348→    const handleError = (error: Error) => {
   349→      if (
   350→        matcher[INTERNAL_MATCHER_FLAG] === true &&
   351→        !(error instanceof JestAssertionError) &&
   352→        error.name !== 'PrettyFormatPluginError' &&
   353→        // Guard for some environments (browsers) that do not support this feature.
   354→        Error.captureStackTrace
   355→      ) {
   356→        // Try to remove this and deeper functions from the stack trace frame.
   357→        Error.captureStackTrace(error, throwingMatcher);
   358→      }
   359→      throw error;
   360→    };
   361→
   362→    let potentialResult: ExpectationResult;
   363→
   364→    try {
   365→      potentialResult =
   366→        matcher[INTERNAL_MATCHER_FLAG] === true
   367→          ? matcher.call(matcherContext, actual, ...args)
   368→          : // It's a trap specifically for inline snapshot to capture this name
   369→            // in the stack trace, so that it can correctly get the custom matcher
   370→            // function call.
   371→            (function __EXTERNAL_MATCHER_TRAP__() {
   372→              return matcher.call(matcherContext, actual, ...args);
   373→            })();
   374→
   375→      if (isPromise(potentialResult)) {
   376→        const asyncError = new JestAssertionError();
   377→        if (Error.captureStackTrace) {
   378→          Error.captureStackTrace(asyncError, throwingMatcher);
   379→        }
   380→
   381→        return potentialResult
   382→          .then(aResult => processResult(aResult, asyncError))
   383→          .catch(handleError);
   384→      } else {
   385→        return processResult(potentialResult);
   386→      }
   387→    } catch (error: any) {
   388→      return handleError(error);
   389→    }
   390→  };
   391→
   392→expect.extend = (matchers: MatchersObject) =>
   393→  setMatchers(matchers, false, expect);
   394→
   395→expect.addEqualityTesters = customTesters =>
   396→  addCustomEqualityTesters(customTesters);
   397→
   398→expect.anything = anything;
   399→expect.any = any;
   400→
   401→expect.not = {
   402→  arrayContaining: arrayNotContaining,
   403→  arrayOf: notArrayOf,
   404→  closeTo: notCloseTo,
   405→  objectContaining: objectNotContaining,
   406→  stringContaining: stringNotContaining,
   407→  stringMatching: stringNotMatching,
   408→};
   409→
   410→expect.arrayContaining = arrayContaining;
   411→expect.arrayOf = arrayOf;
   412→expect.closeTo = closeTo;
   413→expect.objectContaining = objectContaining;
   414→expect.stringContaining = stringContaining;
   415→expect.stringMatching = stringMatching;
   416→
   417→const _validateResult = (result: any) => {
   418→  if (
   419→    typeof result !== 'object' ||
   420→    typeof result.pass !== 'boolean' ||
   421→    (result.message &&
   422→      typeof result.message !== 'string' &&
   423→      typeof result.message !== 'function')
   424→  ) {
   425→    throw new Error(
   426→      'Unexpected return from a matcher function.\n' +
   427→        'Matcher functions should ' +
   428→        'return an object in the following format:\n' +
   429→        '  {message?: string | function, pass: boolean}\n' +
   430→        `'${matcherUtils.stringify(result)}' was returned`,
   431→    );
   432→  }
   433→};
   434→
   435→function assertions(expected: number): void {
   436→  const error = new ErrorWithStack(undefined, assertions);
   437→
   438→  setState({
   439→    expectedAssertionsNumber: expected,
   440→    expectedAssertionsNumberError: error,
   441→  });
   442→}
   443→function hasAssertions(...args: Array<unknown>): void {
   444→  const error = new ErrorWithStack(undefined, hasAssertions);
   445→
   446→  matcherUtils.ensureNoExpected(args[0], '.hasAssertions');
   447→  setState({
   448→    isExpectingAssertions: true,
   449→    isExpectingAssertionsError: error,
   450→  });
   451→}
   452→
   453→// add default jest matchers
   454→setMatchers(matchers, true, expect);
   455→setMatchers(spyMatchers, true, expect);
   456→setMatchers(toThrowMatchers, true, expect);
   457→
   458→expect.assertions = assertions;
   459→expect.hasAssertions = hasAssertions;
   460→expect.getState = getState;
   461→expect.setState = setState;
   462→expect.extractExpectedAssertionsErrors = extractExpectedAssertionsErrors;
   463→
   464→export default expect;
   465→

