    expect([1, () => {}]).toStrictEqual([1, jestExpect.optionalFn()]);
    expect([1, jestExpect.optionalFn()]).toStrictEqual([1, () => {}]);
    // with undefined
    expect({a: 1, b: undefined}).toStrictEqual({
